trigger.body:

   v_identifier VARCHAR(40);

BEGIN

   IF AD_isTriggerEnabled()='N' THEN RETURN;
   END IF;

    IF  (INSERTING) THEN

      IF (COALESCE(:NEW.M_PRODUCT_ID, 'ND') <> 'ND' ) THEN

        SELECT value 
        INTO v_identifier
        FROM M_PRODUCT  
        WHERE M_PRODUCT_ID = :NEW.M_PRODUCT_ID;

        :NEW.em_ssip_identifier := v_identifier;       

      END IF; 

    END IF;


    IF  (UPDATING ) THEN

      IF (COALESCE(:NEW.M_PRODUCT_ID, 'ND') <> 'ND' ) THEN

        SELECT value 
        INTO v_identifier
        FROM M_PRODUCT  
        WHERE M_PRODUCT_ID = :NEW.M_PRODUCT_ID;

        :NEW.em_ssip_identifier := v_identifier;

      END IF; 

    END IF;    

    END SSIP_UPDATEIDENTIFIER_TRG
